// ── Construir consulta Gmail (modo "today" / "range") ───────────────────────
// Lee la configuración del nodo "Configuración" y arma el parámetro de búsqueda
// `q` de Gmail usando timestamps epoch en segundos, para evitar ambigüedad de
// zona horaria (el contenedor de n8n suele estar en UTC; Lima es UTC-5).
//
//   mode = "today" -> correos del día de hoy (en la zona horaria configurada)
//   mode = "range" -> correos entre startDate y endDate (ambos inclusive)

const cfg = $input.first().json;

const tzOffset = Number(cfg.tzOffsetHours ?? -5);          // Lima = -5
const mode = String(cfg.mode || 'today').toLowerCase();

// epoch (segundos) del inicio del día local para una fecha "wall clock" local
function startOfDayEpoch(y, monthIndex, d) {
  return Math.floor(Date.UTC(y, monthIndex, d, 0, 0, 0) / 1000) - tzOffset * 3600;
}

let afterEpoch, beforeEpoch;

if (mode === 'range') {
  if (!cfg.startDate || !cfg.endDate) {
    throw new Error('El modo "range" requiere startDate y endDate en formato YYYY-MM-DD.');
  }
  const [sy, sm, sd] = String(cfg.startDate).split('-').map(Number);
  const [ey, em, ed] = String(cfg.endDate).split('-').map(Number);
  afterEpoch  = startOfDayEpoch(sy, sm - 1, sd);
  beforeEpoch = startOfDayEpoch(ey, em - 1, ed) + 86400;  // incluye el endDate completo
} else {
  // today, en la zona horaria configurada
  const localMs = Date.now() + tzOffset * 3600 * 1000;
  const ld = new Date(localMs);
  afterEpoch  = startOfDayEpoch(ld.getUTCFullYear(), ld.getUTCMonth(), ld.getUTCDate());
  beforeEpoch = afterEpoch + 86400;
}

let q = `after:${afterEpoch} before:${beforeEpoch}`;

// Filtro opcional por palabras clave (configurable y ampliable)
if (cfg.keywordFilterEnabled && Array.isArray(cfg.keywords) && cfg.keywords.length) {
  const kw = cfg.keywords.map(k => `"${k}"`).join(' OR ');
  q += ` (${kw})`;
}

return [{
  json: {
    gmailQuery: q,
    reviewMode: mode,
    afterEpoch,
    beforeEpoch,
    afterIso:  new Date(afterEpoch  * 1000).toISOString(),
    beforeIso: new Date(beforeEpoch * 1000).toISOString()
  }
}];

// ── Normalizar correo (SOLO texto + REFERENCIAS de adjuntos) ────────────────
// Requiere que el nodo Gmail use "Simplify = OFF" para recibir el payload
// completo (con payload.headers y payload.parts).
//
// Produce, por cada correo, un item con:
//   • claves = columnas de email_trace (solo texto)
//   • attachments[] = referencias de adjuntos (sin binarios) para el siguiente nodo
//
// Los binarios NUNCA se descargan ni almacenan. De cada adjunto se guarda
// filename + attachmentId + enlace al correo, para ubicarlo luego en Gmail.

const qinfo = $('Construir consulta Gmail').first().json;
const out = [];

function headerVal(payload, name) {
  if (!payload || !Array.isArray(payload.headers)) return '';
  const h = payload.headers.find(x => (x.name || '').toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}

function decodeB64Url(data) {
  if (!data) return '';
  const b64 = data.replace(/-/g, '+').replace(/_/g, '/');
  try { return Buffer.from(b64, 'base64').toString('utf-8'); } catch (e) { return ''; }
}

function stripHtml(html) {
  return html
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

for (const item of $input.all()) {
  const m = item.json;
  const payload = m.payload || {};

  let textPlain = '';
  let textHtml = '';
  const attachments = [];

  function walk(part) {
    if (!part) return;
    const mime = part.mimeType || '';
    const filename = part.filename || '';

    if (filename && filename.length > 0) {
      // Adjunto -> SOLO referencia (sin binario)
      attachments.push({
        filename,
        mime_type: mime,
        size_bytes: (part.body && part.body.size) || 0,
        attachment_id: (part.body && part.body.attachmentId) || ''
      });
    } else if (mime === 'text/plain' && part.body && part.body.data) {
      textPlain += decodeB64Url(part.body.data);
    } else if (mime === 'text/html' && part.body && part.body.data) {
      textHtml += decodeB64Url(part.body.data);
    }
    if (Array.isArray(part.parts)) part.parts.forEach(walk);
  }
  walk(payload);

  let bodyText = textPlain.trim();
  if (!bodyText && textHtml) bodyText = stripHtml(textHtml);
  if (!bodyText) bodyText = m.snippet || '';

  // Fecha: preferir internalDate (epoch ms); si no, header Date
  let emailDateIso = null;
  if (m.internalDate) {
    const d = new Date(Number(m.internalDate));
    if (!isNaN(d.getTime())) emailDateIso = d.toISOString();
  }
  if (!emailDateIso) {
    const d = new Date(headerVal(payload, 'Date'));
    if (!isNaN(d.getTime())) emailDateIso = d.toISOString();
  }

  const messageId = m.id;
  const gmailLink = `https://mail.google.com/mail/u/0/#all/${messageId}`;

  out.push({
    json: {
      // ── columnas de email_trace ──
      message_id:      messageId,
      thread_id:       m.threadId,
      from_address:    headerVal(payload, 'From'),
      to_addresses:    headerVal(payload, 'To'),
      cc_addresses:    headerVal(payload, 'Cc'),
      subject:         headerVal(payload, 'Subject'),
      email_date:      emailDateIso,
      body_text:       bodyText,
      snippet:         m.snippet || '',
      has_attachments: attachments.length > 0,
      gmail_link:      gmailLink,
      search_query:    qinfo.gmailQuery,
      review_mode:     qinfo.reviewMode,
      // ── auxiliar para "Expandir adjuntos" (lo ignora el insert de trazabilidad) ──
      attachments
    }
  });
}

return out;

// ── Expandir adjuntos (una fila por referencia de adjunto) ──────────────────
// Toma la salida del normalizador y emite un item por cada adjunto, con las
// claves = columnas de email_attachment_ref. Si el correo no tiene adjuntos,
// no emite nada para ese correo.

const out = [];

for (const item of $input.all()) {
  const m = item.json;
  const atts = Array.isArray(m.attachments) ? m.attachments : [];
  for (const a of atts) {
    out.push({
      json: {
        message_id:    m.message_id,
        thread_id:     m.thread_id,
        filename:      a.filename || '',
        mime_type:     a.mime_type || '',
        size_bytes:    a.size_bytes || 0,
        attachment_id: a.attachment_id || '',
        gmail_link:    m.gmail_link
      }
    });
  }
}

return out;
